const theme = {
  // App color tokens (updated per user request)
  primary: '#2563EB', // Royal Blue - headers and primary buttons
  success: '#10B981', // Emerald - success states
  warning: '#F59E0B', // Amber - warning/near-deadline
  secondary: '#cdcec9', // neutral soft surface
  button: '#2563EB', // primary color for buttons
  // Text colors
  textPrimary: '#1E293B', // headings
  textSecondary: '#64748B', // supporting/details
  // Backwards compatibility: some files reference `theme.text`
  text: '#1E293B',
  buttonText: '#ffffff',
  // Background stays the soft off-white
  background: '#f5f5f4'
};

export default theme;
